import yaml, glob, re, os
from collections import Counter

def safe_filename\(name\):
    s = name.lower\(\).strip\(\)
    s = re.sub\(r'[^a-z0-9\\u4e00-\\u9fff\\-]', '-', s\)
    s = re.sub\(r'-+', '-', s\).strip\('-'\)
    return s or 'unknown'

all_names = []
for yf in sorted\(glob.glob\('data/**/*.yaml', recursive=True\)\):
    if os.path.basename\(yf\) == 'metadata.yaml':
        continue
    with open\(yf\) as f:
        data = yaml.safe_load\(f\)
    if not data or 'commands' not in data:
        continue
    for cmd in data['commands']:
        name = cmd.get\('name',''\)
        fn = safe_filename\(name\)
        all_names.append\(\(fn, name, yf\)\)

counter = Counter\(fn for fn,_,_ in all_names\)
dups = {k: v for k,v in counter.items\(\) if v > 1}
print\(f'总命令: {len\(all_names\)}, 唯一文件名: {len\(counter\)}, 冲突: {len\(dups\)}'\)
for fn, cnt in sorted\(dups.items\(\), key=lambda x: -x[1]\)[:20]:
    sources = [\(name, yf\) for f,name,yf in all_names if f == fn]
    print\(f'  {fn} \({cnt}x\): {sources}'\)
"
)

